def sort_patients(patient_info)
  # Separate elderly and younger patients
  elderly_patients = patient_info.select { |patient| patient[1] >= 60 }
  younger_patients = patient_info.select { |patient| patient[1] < 60 }

  # Sort elderly patients by age in descending order, maintaining original order for ties
  sorted_elderly_patients = elderly_patients.sort_by { |patient| [-patient[1], patient_info.index(patient)] }

  # Sort younger patients by registration order
  sorted_younger_patients = younger_patients.sort_by { |patient| patient_info.index(patient) }

  # Combine the sorted lists
  sorted_patients = sorted_elderly_patients + sorted_younger_patients

  sorted_patients
end

# Example usage
